import sailpoint.object.*;
import sailpoint.tools.*;
import java.util.*;

workflowStartTime = new Date();
requestId = UUID.randomUUID().toString();
log.info("Request ID: " + requestId);

List errors = new ArrayList();
if (null == applicationName || applicationName.trim().isEmpty()) {
  errors.add("applicationName required");
}
if (null == groupName || groupName.trim().isEmpty()) {
  errors.add("groupName required");
}
if (null == groupDescription || groupDescription.trim().isEmpty()) {
  errors.add("groupDescription required");
}
if (null == groupOwner || groupOwner.trim().isEmpty()) {
  errors.add("groupOwner required");
}
if (null == groupType || groupType.trim().isEmpty()) {
  errors.add("groupType required");
}
if (null == groupScope || groupScope.trim().isEmpty()) {
  errors.add("groupScope required");
}
if (null == organizationalUnit || organizationalUnit.trim().isEmpty()) {
  errors.add("organizationalUnit required");
}

if (errors.size() > 0) {
  errorMessage = "Validation Failed: " + errors.toString();
  isSuccess = false;
  return false;
}

isSuccess = true;
return true;

log.info("Getting AD application: " + applicationName);
adApplication = context.getObjectByName(sailpoint.object.Application.class, applicationName);
if (null == adApplication) {
  errorMessage = "Application not found: " + applicationName;
  isSuccess = false;
  return false;
}
isSuccess = true;
return true;

import sailpoint.object.*;
import java.util.*;

log.info("Building provisioning plan");
try {
  ProvisioningPlan plan = new ProvisioningPlan();
  ProvisioningPlan.AccountRequest acctReq = new ProvisioningPlan.AccountRequest(
    ProvisioningPlan.AccountRequest.Type.Create, applicationName, null, null);

  Map attributes = new HashMap();
  attributes.put("sAMAccountName", groupName);
  attributes.put("cn", groupName);
  attributes.put("displayName", groupName);
  attributes.put("description", groupDescription);
  attributes.put("groupType", groupType);
  attributes.put("groupScope", groupScope);
  attributes.put("ou", organizationalUnit);
  attributes.put("managedBy", groupOwner);

  if (null != groupEmail && !groupEmail.trim().isEmpty()) {
    attributes.put("mail", groupEmail);
  }
  if (null != additionalAttributes && additionalAttributes.size() > 0) {
    attributes.putAll(additionalAttributes);
  }

  for (String attrName : attributes.keySet()) {
    acctReq.add(new ProvisioningPlan.AttributeRequest(attrName, 
      ProvisioningPlan.Operation.Set, attributes.get(attrName)));
  }

  plan.add(acctReq);
  workflow.put("provisioningPlan", plan);
  isSuccess = true;
  return true;
} catch (Exception e) {
  errorMessage = "Error building plan: " + e.getMessage();
  isSuccess = false;
  return false;
}

import sailpoint.object.*;

log.info("Executing provisioning plan");
try {
  ProvisioningPlan plan = (ProvisioningPlan) workflow.get("provisioningPlan");
  if (null == plan) {
    errorMessage = "Plan not found";
    isSuccess = false;
    return false;
  }

  sailpoint.connector.Connector connector = adApplication.getConnector();
  if (null == connector) {
    errorMessage = "Connector not found";
    isSuccess = false;
    return false;
  }

  connector.provision(context, adApplication, plan);
  log.info("Group created successfully");
  isSuccess = true;
  return true;
} catch (Exception e) {
  errorMessage = "Error: " + e.getMessage();
  isSuccess = false;
  return false;
}

import sailpoint.object.*;
import java.util.*;

try {
  Date endTime = new Date();
  long duration = endTime.getTime() - workflowStartTime.getTime();

  AuditEvent event = new AuditEvent();
  event.setAction("CreateADGroup");
  event.setSource("Workflow");
  event.setInterface("API");
  event.setStatus("SUCCESS");
  event.setComment("Group: " + groupName + " created in " + duration + "ms");

  Map attrs = new HashMap();
  attrs.put("requestId", requestId);
  attrs.put("groupName", groupName);
  event.setAttributes(attrs);

  context.saveObject(event);
  context.commitTransaction();
} catch (Exception e) {
  log.error("Audit error: " + e.getMessage());
}

import sailpoint.object.*;
import java.util.*;

try {
  AuditEvent event = new AuditEvent();
  event.setAction("CreateADGroup");
  event.setSource("Workflow");
  event.setInterface("API");
  event.setStatus("FAILED");
  event.setComment("Error: " + errorMessage);

  Map attrs = new HashMap();
  attrs.put("requestId", requestId);
  attrs.put("error", errorMessage);
  event.setAttributes(attrs);

  context.saveObject(event);
  context.commitTransaction();
} catch (Exception e) {
  log.error("Error logging: " + e.getMessage());
}
